import { Chain, ChainType, chainToChainType } from '@layerzerolabs/lz-definitions'

import { Address as AddressInterface } from './address'
import * as aptos from './aptos'
import * as evm from './evm'
import * as initia from './initia'
import * as solana from './solana'
import * as ton from './ton'
import * as tron from './tron'

export const Address = {
    from: (address: string | Uint8Array, chain: Chain): AddressInterface => {
        const chainType = chainToChainType(chain)
        switch (chainType) {
            case ChainType.EVM:
                if (chain === Chain.TRON) {
                    return tron.Address.from(address)
                }
                return evm.Address.from(address)
            case ChainType.APTOS:
            case ChainType.SUI: // TODO: use Sui address
                return aptos.Address.from(address)
            case ChainType.INITIA:
                return initia.Address.from(address)
            case ChainType.SOLANA:
                return solana.Address.from(address)
            case ChainType.TON:
                return ton.Address.from(address)
            default:
                throw new Error(`Unsupported chain type: ${chainType}`)
        }
    },
}
