import * as secp256k1 from '@noble/secp256k1'

import { normalizePrivateKey } from './internal'

/**
 * Signs a hash using the secp256k1 algorithm.
 *
 * @param {Uint8Array} hash - The hash to sign, must be 32 bytes long.
 * @param {string | Uint8Array | bigint} privateKey - The private key in hex format, Uint8Array, or bigint.
 * @returns {Promise<Uint8Array>} A promise that resolves to the signature.
 * @throws {Error} If the hash is not 32 bytes long or the signature is invalid.
 */
export async function signHash(hash: Uint8Array, privateKey: string | Uint8Array | bigint): Promise<Uint8Array> {
    if (hash.length !== 32) {
        throw new Error('Hash must be 32 bytes long')
    }

    privateKey = normalizePrivateKey(privateKey)
    const pubKey = secp256k1.getPublicKey(privateKey, false)

    // refer to: https://github.com/paulmillr/noble-secp256k1/tree/1.7.1#signmsghash-privatekey
    const [signature, recoveryId] = await secp256k1.sign(hash, privateKey, {
        // recovered - true indicates the recovered bit should be included in the result
        recovered: true,
        // canonical - true makes signatures compatible with libsecp256k1, false makes signatures compatible with openssl
        canonical: true,
        // der - whether the returned signature should be in DER format. If false, it would be in Compact format (32-byte r + 32-byte s)
        der: false,
        // extraEntropy - When true, it would automatically be filled with 32 bytes of cryptographically secure entropy. Strongly recommended to pass true to improve security:
        extraEntropy: undefined,
    })

    const isValid = secp256k1.verify(signature, hash, pubKey, { strict: true })
    if (!isValid) {
        throw new Error('Invalid signature')
    }

    return Uint8Array.from([...signature, recoveryId])
}

/**
 * Gets the public key corresponding to the given private key using the secp256k1 algorithm.
 *
 * @param {string | Uint8Array | bigint} privateKey - The private key in hex format, Uint8Array, or bigint.
 * @returns {Promise<Uint8Array>} A promise that resolves to the public key.
 */
export async function getPublicKey(privateKey: string | Uint8Array | bigint): Promise<Uint8Array> {
    privateKey = normalizePrivateKey(privateKey)
    return Promise.resolve(secp256k1.getPublicKey(privateKey, false))
}
