import { SignAlgorithm } from './constant'
export * from './keypair'
export * from './constant'
import * as ed25519 from './ed25519'
import * as secp256k1 from './secp256k1'

/**
 * Signs a hash using the specified signing algorithm.
 *
 * @param {Uint8Array} hash - The hash to sign, must be 32 bytes long.
 * @param {string | Uint8Array} privateKey - The private key in hex format or Uint8Array.
 * @param {SignAlgorithm} algorithm - The signing algorithm to use.
 * @returns {Promise<Uint8Array>} A promise that resolves to the signature.
 * @throws {Error} If the hash is not 32 bytes long or the algorithm is unsupported.
 */
export async function signHash(
    hash: Uint8Array,
    privateKey: string | Uint8Array,
    algorithm: SignAlgorithm
): Promise<Uint8Array> {
    if (hash.length !== 32) {
        throw new Error('Hash must be 32 bytes long')
    }

    // privKey should be a hex string without 0x prefix
    // refer to: https://github.com/paulmillr/noble-secp256k1/blob/5ed251242bf065aeb22a54bb42eee1f67e7c77ce/index.ts#L130
    const privKey =
        typeof privateKey === 'string' ? privateKey.replace(/^0x/, '') : Buffer.from(privateKey).toString('hex')
    switch (algorithm) {
        case SignAlgorithm.SECP256K1:
            return secp256k1.signHash(hash, privKey)
            break
        case SignAlgorithm.ED25519:
            return ed25519.signHash(hash, privKey)
            break
        default:
            throw new Error(`Unsupported algorithm: ${algorithm}`)
    }
}

export { secp256k1, ed25519 }
