/**
 * Normalizes the private key to a string or Uint8Array.
 * - `getPublicKey` accepts bigint but `sign` does not, in ed25519.
 * - A string privateKey should not have a 0x prefix, in ed25519.
 *
 * @param {string | Uint8Array | bigint} privateKey - The private key to normalize.
 * @returns {string | Uint8Array} The normalized private key.
 */
export function normalizePrivateKey(privateKey: string | Uint8Array | bigint): string | Uint8Array {
    if (typeof privateKey === 'string') {
        return privateKey.replace(/^0x/, '')
    } else if (typeof privateKey === 'bigint') {
        return privateKey.toString(16).padStart(64, '0') // the private key is 32 bytes for ed25519 and secp256k1
    } else {
        return privateKey
    }
}
